class DisjointSet {

    /* Initialize all accounts as separate groups */
    constructor(size) {
        parent = array of size 'size' filled with -1
    }

    /* Find the root parent of a given node */
    find(node) {
        if parent[node] < 0 {
            return node
        }
        parent[node] = find(parent[node])
        return parent[node]
    }

    /* Merge two groups by their sizes */
    unionSize(a, b) {
        parent_a = find(a)
        parent_b = find(b)

        if parent_a != parent_b {
            if parent[parent_a] < parent[parent_b] {
                temp = parent[parent_b]
                parent[parent_b] = parent_a
                parent[parent_a] += temp
            } else {
                temp = parent[parent_a]
                parent[parent_a] = parent_b
                parent[parent_b] += temp
            }
        }
    }
}

/* Main function to merge user profiles */
mergeUserProfile(info) {

    /* Step 1: Initialization */
    n = size of info
    disSet = new DisjointSet(n)
    emailToIndex = empty map

    /* Step 2: Merge accounts with shared emails */
    for i = 0 to n - 1 {
        len = size of info[i]
        for j = 1 to len - 1 {
            email = info[i][j]
            if email not in emailToIndex {
                emailToIndex[email] = i
            } else {
                disSet.unionSize(i, emailToIndex[email])
            }
        }
    }

    /* Step 3: Prepare answer structure */
    ans = list of n empty lists
    for i = 0 to n - 1 {
        ans[i].append(info[i][0])
    }

    /* Step 4: Group emails under representative parent */
    for each (email, index) in emailToIndex {
        parentIndex = disSet.find(index)
        ans[parentIndex].append(email)
    }

    /* Step 5: Sort and collect merged accounts */
    result = empty list
    for i = 0 to n - 1 {
        if disSet.parent[i] < 0 {
            sort(ans[i] from position 1 till end)
            result.append(ans[i])
        }
    }

    /* Step 6: Return the merged and sorted profiles */
    return result
}
