class Solution {
    public List<List<String>> mergeUserProfile(List<List<String>> info) {
        int n = info.size();
        DisjointSet disSet = new DisjointSet(n);
        Map<String, Integer> m = new TreeMap<>();

        for (int i = 0; i < n; i++) {
            int len = info.get(i).size();
            for (int j = 1; j < len; j++) {
                String email = info.get(i).get(j);
                if (!m.containsKey(email)) {
                    m.put(email, i);
                } else {
                    disSet.unionSize(i, m.get(email));
                }
            }
        }

        List<List<String>> ans = new ArrayList<>();
        for (int i = 0; i < n; i++) {
            ans.add(new ArrayList<>());
            ans.get(i).add(info.get(i).get(0));
        }

        for (Map.Entry<String, Integer> x : m.entrySet()) {
            String email = x.getKey();
            int node = x.getValue();
            int overallParent = disSet.find(node);
            ans.get(overallParent).add(email);
        }

        List<List<String>> ans2 = new ArrayList<>();

        for (int i = 0; i < n; i++) {
            if (disSet.parent[i] < 0) {
                Collections.sort(ans.get(i).subList(1, ans.get(i).size()));
                ans2.add(ans.get(i));
            }
        }

        return ans2;
    }
}

