class DisjointSet {
    constructor(size) {
        this.parent = new Array(size).fill(-1);
    }

    find(node) {
        if (this.parent[node] < 0) {
            return node;
        }
        this.parent[node] = this.find(this.parent[node]);
        return this.parent[node];
    }

    unionSize(a, b) {
        const parentA = this.find(a);
        const parentB = this.find(b);

        if (parentA !== parentB) {
            if (this.parent[parentA] < this.parent[parentB]) {
                const temp = this.parent[parentB];
                this.parent[parentB] = parentA;
                this.parent[parentA] += temp;
            } else {
                const temp = this.parent[parentA];
                this.parent[parentA] = parentB;
                this.parent[parentB] += temp;
            }
        }
    }
}

class Solution {
    static mergeUserProfile(info) {
        const n = info.length;
        const disSet = new DisjointSet(n);
        const m = new Map();

        for (let i = 0; i < n; i++) {
            const len = info[i].length;
            for (let j = 1; j < len; j++) {
                const email = info[i][j];
                if (!m.has(email)) {
                    m.set(email, i);
                } else {
                    disSet.unionSize(i, m.get(email));
                }
            }
        }

        const ans = Array.from({ length: n }, () => []);

        for (let i = 0; i < n; i++) {
            ans[i].push(info[i][0]);
        }

        const sortedEntries = Array.from(m.entries()).sort((a, b) => a[0].localeCompare(b[0]));
        for (const [email, node] of sortedEntries) {
            const overallParent = disSet.find(node);
            ans[overallParent].push(email);
        }

        const ans2 = [];

        for (let i = 0; i < n; i++) {
            if (disSet.parent[i] < 0) {
                const head = ans[i][0];
                const emails = ans[i].slice(1).sort();
                ans2.push([head, ...emails]);
            }
        }

        return ans2;
    }
}

