        if (parent_a != parent_b) {
            if (parent[parent_a] < parent[parent_b]) {
                int temp = parent[parent_b];
                parent[parent_b] = parent_a;
                parent[parent_a] += temp;
            } else {
                int temp = parent[parent_a];
                parent[parent_a] = parent_b;
                parent[parent_b] += temp;
            }
        }
    }
}

class Solution {
    public List<Integer> numberOfIslands2(int m, int n, List<int[]> operations) {
        DisjointSet dis_set = new DisjointSet(m * n);
        int[][] grid = new int[m][n];
        List<Integer> ans = new ArrayList<>();
        int count = 0;

        for (int[] op : operations) {
            int r = op[0];
            int c = op[1];

            if (grid[r][c] == 0) {
                count++;
                grid[r][c] = 1;
                int node = n * r + c;

                if (r > 0 && grid[r - 1][c] == 1) {
                    int adj_node = n * (r - 1) + c;
                    if (dis_set.find(adj_node) != dis_set.find(node)) {
                        count--;
                        dis_set.unionSize(node, adj_node);
                    }
                }

                if (r + 1 < m && grid[r + 1][c] == 1) {
                    int adj_node = n * (r + 1) + c;
                    if (dis_set.find(adj_node) != dis_set.find(node)) {
                        count--;
                        dis_set.unionSize(node, adj_node);
                    }
                }

                if (c > 0 && grid[r][c - 1] == 1) {
                    int adj_node = n * r + (c - 1);
                    if (dis_set.find(adj_node) != dis_set.find(node)) {
                        count--;
                        dis_set.unionSize(node, adj_node);
                    }
                }

                if (c + 1 < n && grid[r][c + 1] == 1) {
                    int adj_node = n * r + (c + 1);
                    if (dis_set.find(adj_node) != dis_set.find(node)) {
                        count--;
                        dis_set.unionSize(node, adj_node);
                    }
                }
            }

            ans.add(count);
        }

        return ans;
    }
}

