                    curr[j] = prev[j - 1];
                else if (p.charAt(j - 1) == '*')
                    curr[j] = prev[j] || curr[j - 1];
                else
                    curr[j] = false;
            }
            prev = Arrays.copyOf(curr, curr.length);
        }
        return curr[n];
    }

