class Solution {
    static wildCardMatching(s, p) {
        const m = s.length, n = p.length;
        let prev = Array(n + 1).fill(false);
        let curr = Array(n + 1).fill(false);
        prev[0] = true;
        for (let j = 1; j <= n; j++)
            if (p[j - 1] === '*') prev[j] = prev[j - 1];
        for (let i = 1; i <= m; i++) {
            curr[0] = false;
            for (let j = 1; j <= n; j++) {
                if (s[i - 1] === p[j - 1] || p[j - 1] === '?')
                    curr[j] = prev[j - 1];
                else if (p[j - 1] === '*')
                    curr[j] = prev[j] || curr[j - 1];
                else curr[j] = false;
            }
            prev = [...curr];
        }
        return curr[n];
    }
}

