import java.util.*;

class Solution {
    public int minSwaps(int[] arr) {
        int n = arr.length;

        int[] sortedArr = arr.clone();
        Arrays.sort(sortedArr);

        HashMap<Integer, Integer> position = new HashMap<>();
        for (int i = 0; i < n; i++) {
            position.put(sortedArr[i], i);
        }

        int swaps = 0;
        int i = 0;

