            if (position.get(arr[i]) == i) {
                i++;
            } else {
                int correctIndex = position.get(arr[i]);
                int temp = arr[i];
                arr[i] = arr[correctIndex];
                arr[correctIndex] = temp;
                swaps++;
            }
        }

        return swaps;
    }
}

