public:
    vector<int> nearestSmallerElement(vector<int>& arr) {
        int n = (int)arr.size();
        vector<int> ans(n, -1);

        for (int i = 0; i < n; i++) {
            for (int j = i - 1; j >= 0; j--) {
                if (arr[j] < arr[i]) {
                    ans[i] = arr[j];
                    break;
                }
            }
        }

        return ans;
    }
};

