class Solution {
    static nearestSmallerElement(arr) {
        const n = arr.length;
        const stk = [];
        const ans = new Array(n).fill(-1);

        for (let i = 0; i < n; i++) {
            while (stk.length > 0 && stk[stk.length - 1] >= arr[i]) {
                stk.pop();
            }

            if (stk.length > 0) {
                ans[i] = stk[stk.length - 1];
            }

            stk.push(arr[i]);
        }

        return ans;
    }
}

