class Node {
public:
    int key, value;
    Node* prev;
    Node* next;
    Node(int _key, int _value) {
        key = _key;
        value = _value;
        prev = next = nullptr;
    }
};

class solution {
    unordered_map<int, Node*> map;
    Node* head;
    Node* tail;
    int capacity;

public:
    solution(int _capacity) {
        capacity = _capacity;
        head = new Node(0, 0);
        tail = new Node(0, 0);
        head->next = tail;
        tail->prev = head;
    }

    int get(int key) {
        if (map.count(key)) {
            Node* node = map[key];
            remove(node);
            insert(node);
            return node->value;
        }
        return -1;
    }

    void put(int key, int value) {
        if (map.count(key)) {
            remove(map[key]);
        }
        if (map.size() == capacity) {
            remove(tail->prev);
        }
        insert(new Node(key, value));
    }

private:
    void remove(Node* node) {
        map.erase(node->key);
        node->prev->next = node->next;
        node->next->prev = node->prev;
    }

    void insert(Node* node) {
        map[node->key] = node;
        node->next = head->next;
        head->next->prev = node;
        head->next = node;
        node->prev = head;
    }
};

