class Solution {
    static heapifyDown(heap, i) {
        const n = heap.length;
        while (true) {
            let smallest = i;
            const left = 2 * i + 1;
            const right = 2 * i + 2;

            if (left < n && heap[left] < heap[smallest]) {
                smallest = left;
            }

            if (right < n && heap[right] < heap[smallest]) {
                smallest = right;
            }

            if (smallest !== i) {
                [heap[i], heap[smallest]] = [heap[smallest], heap[i]];
                i = smallest;
            } else {
                break;
            }
        }
    }

    static heapifyUp(heap, i) {
        while (i > 0) {
            const parent = Math.floor((i - 1) / 2);
            if (heap[i] < heap[parent]) {
                [heap[i], heap[parent]] = [heap[parent], heap[i]];
                i = parent;
            } else {
                break;
            }
        }
    }

    static push(heap, value) {
        heap.push(value);
        Solution.heapifyUp(heap, heap.length - 1);
    }

    static pop(heap) {
        const top = heap[0];
        const last = heap.pop();

        if (heap.length > 0) {
            heap[0] = last;
            Solution.heapifyDown(heap, 0);
        }

        return top;
    }

    static maxItemCount(weight) {
        const pq = [];

        for (const x of weight) {
            Solution.push(pq, x);
        }

        let sum = 0;
        let ans = 0;

        while (pq.length > 0) {
            sum += Solution.pop(pq);
            if (sum > 5000) {
                break;
            }
            ans++;
        }

        return ans;
    }
}

