#include <bits/stdc++.h>
using namespace std;

class solution {
public:
    int sumOfSquares(int num) {
        int sum = 0;
        while (num > 0) {
            int digit = num % 10;
            sum += digit * digit;
            num /= 10;
        }
        return sum;
    }

    bool isStableChargeCycle(int num) {
        unordered_set<int> seen;

        while (num != 1 && seen.find(num) == seen.end()) {
            seen.insert(num);
            num = sumOfSquares(num);
        }

        return num == 1;
    }
};

