isValidSudokuBoard(board) {
    rowMask[9] = all 0   /* Tracks digits in each row */
    colMask[9] = all 0   /* Tracks digits in each column */
    boxMask[9] = all 0   /* Tracks digits in each 3×3 box */

    for r from 0 to 8 {
        for c from 0 to 8 {
            if (board[r][c] == '.') continue  /* Skip empty cells */

            d   = board[r][c] - '1'           /* Digit index (0..8) */
            bit = 1 << d                      /* Bit for this digit */
            b   = (r / 3) * 3 + (c / 3)       /* Box index (0..8) */

            /* Check if digit already exists in row, column, or box */
            if ((rowMask[r] & bit) != 0 OR (colMask[c] & bit) != 0 OR (boxMask[b] & bit) != 0)
                return false

            /* Mark digit in row, column, and box */
            rowMask[r] |= bit
            colMask[c] |= bit
            boxMask[b] |= bit
        }
    }
    return true
}
```

