class solution {
public:
    vector<string> formatText(vector<string>& text, int lineWidth) {
        vector<string> result;
        vector<string> currentLine;
        int currentLength = 0;

        for (string& word : text) {
            if (currentLength + word.length() + currentLine.size() > lineWidth) {
                int spaces = lineWidth - currentLength;
                if (currentLine.size() == 1) {
                    result.push_back(currentLine[0] + string(spaces, ' '));
                } else {
                    int evenSpace = spaces / (currentLine.size() - 1);
                    int extraSpace = spaces % (currentLine.size() - 1);
                    string line = currentLine[0];
                    for (int i = 1; i < currentLine.size(); ++i) {
                        line += string(evenSpace + (i <= extraSpace), ' ') + currentLine[i];
                    }
                    result.push_back(line);
                }
                currentLine.clear();
                currentLength = 0;
            }
            currentLine.push_back(word);
            currentLength += word.length();
        }

        string lastLine = currentLine[0];
        for (int i = 1; i < currentLine.size(); ++i) {
            lastLine += " " + currentLine[i];
        }
        lastLine += string(lineWidth - lastLine.length(), ' ');
        result.push_back(lastLine);

        return result;
    }
