```cpp
#include <bits/stdc++.h>
using namespace std;

class solution {
public:
    int minCrystalReplacements(vector<int>& crystals) {
        int n = crystals.size();
        int freq1 = 0, freq2 = 0, freq3 = 0;

        for (int x : crystals) {
            if (x == 1) {
                freq1++;
            } else if (x == 2) {
                freq2++;
            } else {
                freq3++;
            }
        }

        int rep1 = n - freq1;
        int rep2 = n - freq2;
        int rep3 = n - freq3;

        return min({rep1, rep2, rep3});
    }
};

