        PriorityQueue<Pair> pq = new PriorityQueue<>(Comparator.comparingInt(p -> p.data));

        int k = arr.size();
        if (k == 0) return null;

        Node dummy = new Node(0);
        Node cur = dummy;

        for (Node node : arr) {
            if (node != null) {
                pq.add(new Pair(node.data, node));
            }
        }

        while (!pq.isEmpty()) {
            Pair x = pq.poll();

            cur.next = x.node;
            cur = cur.next;

            if (x.node.next != null) {
                pq.add(new Pair(x.node.next.data, x.node.next));
            }
        }

        return dummy.next;
    }
}

