class Solution {
    static swap(heap, i, j) {
        const temp = heap[i];
        heap[i] = heap[j];
        heap[j] = temp;
    }

    static heapifyUp(heap, i) {
        while (i > 0) {
            const parent = Math.floor((i - 1) / 2);
            if (heap[i][0] < heap[parent][0]) {
                Solution.swap(heap, i, parent);
                i = parent;
            } else {
                break;
            }
        }
    }

    static heapifyDown(heap, i) {
        const n = heap.length;
        while (true) {
            let smallest = i;
            const left = 2 * i + 1;
            const right = 2 * i + 2;

            if (left < n && heap[left][0] < heap[smallest][0]) {
                smallest = left;
            }

            if (right < n && heap[right][0] < heap[smallest][0]) {
                smallest = right;
            }

            if (smallest !== i) {
                Solution.swap(heap, i, smallest);
                i = smallest;
            } else {
                break;
            }
        }
    }

    static push(heap, item) {
        heap.push(item);
        Solution.heapifyUp(heap, heap.length - 1);
    }

    static pop(heap) {
        const top = heap[0];
        const last = heap.pop();

        if (heap.length > 0) {
            heap[0] = last;
            Solution.heapifyDown(heap, 0);
        }

        return top;
    }

    static mergeKLists(arr) {
        const pq = [];
        const k = arr.length;

        if (k === 0) return null;

        const dummy = new Node(0);
        let cur = dummy;

        for (let i = 0; i < k; i++) {
            if (arr[i]) {
                Solution.push(pq, [arr[i].data, arr[i]]);
            }
        }

        while (pq.length > 0) {
            const [data, node] = Solution.pop(pq);

            cur.next = node;
            cur = cur.next;

            if (node.next) {
                Solution.push(pq, [node.next.data, node.next]);
            }
        }

        return dummy.next;
    }
}

